(function(w){"use strict";const ID="ratio";function parseDec(v){let s=String(v??"").replace(/,/g,"").trim();const m=s.match(/^([+-]?)(\d+)(?:\.(\d+))?$/);if(!m)return null;const frac=m[3]||"";let n=BigInt((m[2]||"0")+frac);if(m[1]==="-")n=-n;return{n,scale:frac.length}}function abs(n){return n<0n?-n:n}function gcd(a,b){a=abs(a);b=abs(b);while(b){const t=a%b;a=b;b=t}return a||1n}function pow10(n){let r=1n;while(n-->0)r*=10n;return r}function compute(x){const a=parseDec(x.a),b=parseDec(x.b);if(!a||!b)return{error:"두 값을 숫자로 입력해 주세요."};const scale=Math.max(a.scale,b.scale);let A=a.n*pow10(scale-a.scale),B=b.n*pow10(scale-b.scale);if(A===0n&&B===0n)return{error:"두 값이 모두 0일 수는 없습니다."};const g=gcd(A,B);A/=g;B/=g;if(B<0n){A=-A;B=-B}const decimal=B===0n?null:Number(A)/Number(B);return{left:A.toString(),right:B.toString(),ratioText:A.toString()+":"+B.toString(),decimal:Number.isFinite(decimal)?decimal:null,percent:Number.isFinite(decimal)?decimal*100:null}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-ratio-a">A 값</label><input id="hm-ratio-a" class="hm-calc-input" inputmode="decimal" placeholder="예: 12"></div><div class="hm-calc-field"><label for="hm-ratio-b">B 값</label><input id="hm-ratio-b" class="hm-calc-input" inputmode="decimal" placeholder="예: 18"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">비율 단순화</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:a.value,b:b.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");let detail="";if(r.decimal!==null)detail=`<dl><dt>A ÷ B</dt><dd>${api.formatNumber(r.decimal,10)}</dd><dt>백분율</dt><dd>${api.formatNumber(r.percent,8)}%</dd></dl>`;api.setResult(res,api.resultCard("간단한 비",api.escapeHTML(r.ratioText),detail));});reset.addEventListener("click",()=>{a.value=b.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
